package main

import (
	"encoding/xml"
	"fmt"
)

type Config struct {
	XMLName xml.Name `xml:"config"`
	Setings []Setting `xml:"setting"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:"value,attr"`
}

func parseConfig(xmlData []byte) (*Config, error) {
	var config Config
	err := xml.Unmarshal(xmlData, &config)
	if err != nil {
		return nil, err
	}
	return &config, nil
}

func main() {
	xmlData := []byte(`
	<config>
		<setting name="host" value="localhost"/>
		<setting name="port" value="8080"/>
	</config>
	`)

	config, err := parseConfig(xmlData)
	if err != nil {
		fmt.Println("Error parsing XML:", err)
		return
	}

	for _, setting := range config.Setings {
		fmt.Printf("Setting: %s = %s\n", setting.Name, setting.Value)
	}
}